            { group: 'Ecosystem Integrations', items: ['Deep Native integration with Scrivener, Microsoft Word, Google Docs', 'Browser extensions (Chrome, Safari, Edge)', 'Customizable corporate Style Guides and dictionaries', 'Advanced Plagiarism detection (Premium only)'] }
